// Dashboard 7 — TSQMI com Pulso ECG
// Implementação limpa e funcional

const REPO_META = {
  cli:     { label: 'CLI',     color: '#1D9E75' },
  core:    { label: 'Core',    color: '#378ADD' },
  service: { label: 'Service', color: '#D85A30' },
  front:   { label: 'Front',   color: '#D4537E' }
};

// Função msgPulse - Gera pulso ECG para uma transição
function msgPulse(valueA, valueB, timeA, timeB) {
  const SPS = 12; // 12 pontos por transição
  const points = [];
  const delta = valueB - valueA;
  const peakAmplitude = delta * 2.2; // Amplitude do pico 2.2x maior que delta

  // Usar intervalo de tempo fixo de 2 horas entre pontos para garantir visibilidade
  const TWO_HOURS = 2 * 60 * 60 * 1000;
  const timeStep = TWO_HOURS;

  for (let i = 0; i < SPS; i++) {
    const t = i / SPS;
    let v;

    if (t < 0.30) {
      // Base inicial - 30% do tempo no valor inicial
      v = valueA;
    } else if (t < 0.42) {
      // Subida - 12% do tempo subindo ao pico
      const p = (t - 0.30) / 0.12;
      v = valueA + peakAmplitude * Math.sin(p * Math.PI * 0.5);
    } else if (t < 0.56) {
      // Descida - 14% do tempo descendo do pico
      const p = (t - 0.42) / 0.14;
      v = valueA + peakAmplitude * (1 - p);
    } else if (t < 0.68) {
      // Onda de retorno - 12% do tempo com pequena oscilação abaixo do novo valor
      const p = (t - 0.56) / 0.12;
      v = valueB - (delta * 0.15) * Math.sin(p * Math.PI);
    } else {
      // Nova base - 32% do tempo no novo valor
      v = valueB;
    }

    const interpTime = timeA + (timeStep * i);
    points.push([interpTime, v]);
  }

  return points;
}

// Processar dados do PostgreSQL
const repoData = {};
data.series.forEach(series => {
  const refId = series.refId.toLowerCase();
  if (REPO_META[refId]) {
    const timeField = series.fields.find(f => f.name === 'time');
    const valueField = series.fields.find(f => f.name === series.refId);

    if (timeField && valueField && valueField.values.length > 0) {
      repoData[refId] = {
        label: REPO_META[refId].label,
        color: REPO_META[refId].color,
        times: timeField.values,
        values: valueField.values
      };
    }
  }
});

const repos = Object.keys(repoData);
if (repos.length === 0) {
  return {
    title: {
      text: 'Aguardando dados...',
      left: 'center',
      top: 'center',
      textStyle: { fontSize: 14, color: '#888' }
    }
  };
}

const firstRepo = repos[0];
const N = repoData[firstRepo].values.length;

// Releases
const releases = [
  { label: 'R1', dateIndex: 0 },
  { label: 'R2', dateIndex: Math.floor(N / 2) },
  { label: 'RN', dateIndex: N - 1 }
];

// Criar séries com pulso ECG
const series = repos.map(repoKey => {
  const repo = repoData[repoKey];
  const values = repo.values;
  const times = repo.times;

  // Detectar transições
  const transitions = [];
  for (let i = 0; i < values.length - 1; i++) {
    if (values[i] !== values[i + 1]) {
      transitions.push({
        startIdx: i,
        endIdx: i + 1,
        valueA: values[i],
        valueB: values[i + 1],
        timeA: times[i],
        timeB: times[i + 1]
      });
    }
  }

  // Criar índices de transição para pular na linha plana
  const transitionSet = new Set();
  transitions.forEach(t => {
    transitionSet.add(t.startIdx);
    transitionSet.add(t.endIdx);
  });

  // Construir dados finais
  const dataPoints = [];

  // Adicionar pontos da linha plana (exceto transições)
  for (let i = 0; i < values.length; i++) {
    if (!transitionSet.has(i)) {
      dataPoints.push([times[i], values[i]]);
    }
  }

  // Adicionar pulsos ECG
  transitions.forEach(trans => {
    const pulsePoints = msgPulse(trans.valueA, trans.valueB, trans.timeA, trans.timeB);
    dataPoints.push(...pulsePoints);

    // DEBUG: Log da primeira transição do Core
    if (repo.label === 'Core' && transitions.indexOf(trans) === 0) {
      console.log('DEBUG Core - Primeira transição:');
      console.log('  valueA:', trans.valueA, 'valueB:', trans.valueB);
      console.log('  timeA:', new Date(trans.timeA));
      console.log('  timeB:', new Date(trans.timeB));
      console.log('  Pontos gerados:', pulsePoints.length);
      pulsePoints.forEach((pt, idx) => {
        console.log('    [' + idx + ']', new Date(pt[0]).toISOString(), 'valor:', pt[1].toFixed(4));
      });
    }
  });

  // Ordenar por timestamp
  dataPoints.sort((a, b) => a[0] - b[0]);

  return {
    name: repo.label,
    type: 'line',
    smooth: false,
    symbol: 'circle',
    symbolSize: 4,
    showSymbol: true,
    sampling: 'none',
    connectNulls: false,
    lineStyle: {
      color: repo.color,
      width: 2,
      type: 'solid'
    },
    itemStyle: {
      color: repo.color
    },
    data: dataPoints,
    markLine: {
      silent: true,
      symbol: 'none',
      data: releases.map(rel => ({
        xAxis: times[rel.dateIndex],
        label: {
          formatter: rel.label,
          position: 'insideStartTop',
          fontSize: 9,
          fontWeight: 'bold',
          color: '#BA7517'
        },
        lineStyle: {
          color: '#BA7517',
          type: 'dashed',
          width: 1
        }
      }))
    },
    markPoint: {
      symbol: 'circle',
      symbolSize: 6,
      data: releases.map(rel => ({
        coord: [times[rel.dateIndex], values[rel.dateIndex]],
        itemStyle: { color: repo.color }
      }))
    }
  };
});

const isDark = theme.isDark;
const textColor = isDark ? 'rgba(255,255,255,0.7)' : 'rgba(0,0,0,0.6)';
const gridColor = isDark ? 'rgba(255,255,255,0.07)' : 'rgba(0,0,0,0.07)';

return {
  backgroundColor: 'transparent',
  legend: {
    data: repos.map(k => repoData[k].label),
    textStyle: { color: textColor, fontSize: 11 },
    bottom: 0
  },
  tooltip: {
    trigger: 'axis',
    formatter: params => {
      if (!params || params.length === 0) return '';

      const time = params[0].data[0];
      const dt = new Date(time).toLocaleString('pt-BR');

      let html = '<b>' + dt + '</b>';

      params.forEach(p => {
        const val = p.data[1];
        html += '<br/><span style="color:' + p.color + '">■</span> ' + p.seriesName + ': <b>' + val.toFixed(4) + '</b>';
      });

      return html;
    }
  },
  grid: { top: 20, bottom: 50, left: 50, right: 20 },
  xAxis: {
    type: 'time',
    axisLabel: {
      color: textColor,
      fontSize: 10,
      formatter: function(value) {
        const d = new Date(value);
        return String(d.getDate()).padStart(2, '0') + '/' + String(d.getMonth() + 1).padStart(2, '0');
      }
    },
    splitLine: { show: false },
    axisLine: { lineStyle: { color: gridColor } }
  },
  yAxis: {
    type: 'value',
    scale: true,
    axisLabel: {
      color: textColor,
      fontSize: 9,
      formatter: v => v.toFixed(3)
    },
    splitLine: { lineStyle: { color: gridColor } }
  },
  series
};

options.getOption:
// 1. Dicionário de Metadados
const REPO_META = {
  cli: { label: 'CLI', color: '#1D9E75' },
  core: { label: 'Core', color: '#378ADD' },
  service: { label: 'Service', color: '#D85A30' },
  front: { label: 'Front', color: '#D4537E' },
  action: { label: 'Action', color: '#BA7517' },
  ai: { label: 'AI', color: '#7F77DD' },
  parser: { label: 'Parser', color: '#888780' },
};

// Função de resolução para nomes de repositórios longos
function getMetaConfig(rawName) {
  const normalizedName = String(rawName).toLowerCase();
  for (const [key, meta] of Object.entries(REPO_META)) {
    if (normalizedName.includes(key)) return meta;
  }
  return { label: rawName, color: '#888780' };
}

// 2. Extração de Dados
const frame = context.panel.data.series[0];
const names = frame.fields.find(f => f.name === 'name').values.buffer || frame.fields.find(f => f.name === 'name').values;
const datetimes = frame.fields.find(f => f.name === 'datetime').values.buffer || frame.fields.find(f => f.name === 'datetime').values;
const tsqmis = frame.fields.find(f => f.name === 'tsqmi').values.buffer || frame.fields.find(f => f.name === 'tsqmi').values;

// 3. Agrupamento
const groupedData = {};
for (let i = 0; i < names.length; i++) {
  const key = names[i];
  if (!groupedData[key]) {
    groupedData[key] = { datetimes: [], tsqmi: [] };
  }
  groupedData[key].datetimes.push(datetimes[i]);
  groupedData[key].tsqmi.push(tsqmis[i]);
}

// 4. Mapeamento final com aplicação de cor
const repoSeries = Object.keys(groupedData).map(key => {
  const meta = getMetaConfig(key);
  return {
    key,
    label: meta.label,
    color: meta.color,
    datetimes: groupedData[key].datetimes,
    tsqmi: groupedData[key].tsqmi,
  };
});

const releases = [
  { label: 'R1', dateIndex: 0 },
  { label: 'R2', dateIndex: 5 },
  { label: 'RN', dateIndex: repoSeries[0]?.datetimes.length - 1 },
];

function msgPulse(scores, idxList) {
  const SPS = 60;
  const pts = [];
  for (let ii = 0; ii < idxList.length - 1; ii++) {
    const a = scores[idxList[ii]], b = scores[idxList[ii + 1]];
    const delta = b - a, pk = delta * 2.2;
    for (let s = 0; s < SPS; s++) {
      const t = s / SPS;
      let v;
      if (t < 0.30) { v = a; }
      else if (t < 0.42) { const p = (t - 0.30) / 0.12; v = a + pk * Math.sin(p * Math.PI * 0.5); }
      else if (t < 0.56) { const p = (t - 0.42) / 0.14; v = a + pk * (1 - p); }
      else if (t < 0.68) { const p = (t - 0.56) / 0.12; v = b - delta * 0.15 * Math.sin(p * Math.PI); }
      else { v = b; }
      pts.push(Math.max(0.01, Math.min(0.99, v)));
    }
  }
  pts.push(Math.max(0.01, Math.min(0.99, scores[idxList[idxList.length - 1]])));
  return pts;
}

const N = repoSeries[0]?.datetimes.length || 0;
const idxList = Array.from({ length: N }, (_, i) => i);
const SPS = 60;

const isDark = context.grafana.theme.isDark;
const textColor = isDark ? 'rgba(255,255,255,0.7)' : 'rgba(0,0,0,0.6)';
const gridColor = isDark ? 'rgba(255,255,255,0.07)' : 'rgba(0,0,0,0.07)';

const xLabels = [];
idxList.forEach((idx, ii) => {
  if (ii < idxList.length - 1) for (let s = 0; s < SPS; s++) xLabels.push(repoSeries[0].datetimes[idx]);
  else xLabels.push(repoSeries[0].datetimes[idx]);
});

// 5. Configuração das Séries ECharts
const series = repoSeries.map(r => ({
  name: r.label,
  type: 'line',
  smooth: false,
  symbol: 'none',
  // A propriedade itemStyle obriga a legenda a espelhar a cor customizada da linha
  itemStyle: {
    color: r.color,
  },
  lineStyle: {
    color: r.color,
    width: 1.8,
    type: 'solid',
  },
  data: msgPulse(r.tsqmi, idxList),
  markLine: {
    silent: true, symbol: 'none',
    data: releases.map(rel => ({
      xAxis: rel.dateIndex * SPS,
      label: { formatter: rel.label, position: 'insideStartTop', fontSize: 9, fontWeight: 'bold', color: '#BA7517' },
      lineStyle: { color: '#BA7517', type: 'dashed', width: 1 },
    })),
  },
  markPoint: {
    symbol: 'circle', symbolSize: 7,
    data: releases.map(rel => ({
      coord: [rel.dateIndex * SPS, r.tsqmi[rel.dateIndex]],
      itemStyle: { color: r.color },
    })),
  },
}));

const option = {
  backgroundColor: 'transparent',
  legend: {
    data: repoSeries.map(r => r.label),
    textStyle: { color: textColor, fontSize: 11 },
    bottom: 0,
  },
  tooltip: {
    trigger: 'axis',
    formatter: params => {
      const measureIdx = Math.min(Math.floor(params[0].dataIndex / SPS), N - 1);
      const dt = repoSeries[0].datetimes[measureIdx];
      const rel = releases.find(r => r.dateIndex === measureIdx);
      let html = `<b>${dt}</b>`;
      if (rel) html += `<br/><span style="color:#BA7517">● ${rel.label}</span>`;
      repoSeries.forEach(r => {
        const v = r.tsqmi[measureIdx];
        const prev = measureIdx > 0 ? r.tsqmi[measureIdx - 1] : null;
        const delta = prev !== null ? v - prev : null;
        const col = delta !== null ? (delta >= 0 ? '#1D9E75' : '#E24B4A') : textColor;
        html += `<br/><span style="color:${r.color}">■</span> ${r.label}: <b>${v.toFixed(2)}</b>`;
        if (delta !== null) html += ` <span style="color:${col}">${delta >= 0 ? '+' : ''}${delta.toFixed(2)}</span>`;
      });
      return html;
    },
  },
  grid: { top: 20, bottom: 50, left: 50, right: 20 },
  xAxis: {
    type: 'category',
    data: xLabels,
    axisLabel: {
      color: textColor, fontSize: 10,
      interval: SPS * Math.floor(N / 5) - 1,
      formatter: v => v ? v.slice(5, 10).replace('-', '/') : '',
    },
    splitLine: { show: false },
    axisLine: { lineStyle: { color: gridColor } },
  },
  yAxis: {
    type: 'value',
    min: 0, max: 1, interval: 0.25,
    axisLabel: { color: textColor, fontSize: 9, formatter: v => v.toFixed(2) },
    splitLine: { lineStyle: { color: gridColor } },
  },
  series,
};

return option;

